var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIEF_VOICE_NULL_NULL","text":{"KOREA":"제정신이야 강소영 경위!!","JPN":"正気なのか？　マエカワ警部補！！","ENG":"Are you out of your mind, Lieutenant?","TWN":"妳瘋了嗎？姜素英警衛！"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIEF_VOICE_NULL_NULL","text":{"KOREA":"미성년자를 일산화탄소에 중독시키다니! ","JPN":"未成年者を一酸化炭素中毒にさせるなんて！","ENG":"You put a minor at risk of carbon monoxide poisoning! ","TWN":"竟然讓未成年人一氧化碳中毒！"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 기발했죠? 저도 거기 석탄 난로 같은 게 있을 줄은 몰랐는데......","JPN":"はは、奇抜でしたよね？\\n私もそこに石炭ストーブがあるとは思いませんでしたが……","ENG":"Hah hah, that was pretty ingenious, right? I never expected to find a coal stove in a place like that either...","TWN":"哈哈，很有奇效吧？我也沒想到那裡竟然會有煤炭爐……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_VOICE_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"うるさいっ！","ENG":"Shut up!","TWN":"奇效妳個頭啦！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIEF_VOICE_NULL_NULL","text":{"KOREA":"다행히 별 탈이 없었기에 망정이지 후유증이라도 남았으면 어쩔 뻔 했나?!","JPN":"幸い無事だったからよかったものの、後遺症でも残ったらどうするつもりだったんだ！？","ENG":"You're lucky she's alright. What if it left her with any permanent damage?","TWN":"幸好沒出什麼別的事情，要是留下了什麼後遺症，那該怎麼辦？！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그야 엘릭서 복용자들은 재생능력이 좋아서 그 정도로는 영구적인 손상이 남을 리가 없거든요.","JPN":"エリクサーの服用者は再生能力が高いので、\\nその程度で後遺症なんて残るはずないんです。","ENG":"Well, she took the Elixir, so I'm sure she would've healed right up. That's not enough to leave any permanent damage.","TWN":"因為服用聖水的人再生能力都很好，這種程度應該不會留下永久性的傷害啊。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제가 나름대로 다 여러 가지 고려를 해서......","JPN":"私も自分なりにあれこれ工夫して……","ENG":"Trust me, I've considered all the risk factors...","TWN":"我有考慮到各種因素……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIEF_VOICE_NULL_NULL","text":{"KOREA":"됐어! 말대꾸하지 말고 가서 시말서나 쓰게!","JPN":"口答えはいらん！　今すぐ始末書を書け！","ENG":"Enough! I don't want to hear your excuses. Expect to be given a reprimand for this!","TWN":"夠了！別頂嘴了，給我去寫悔過書！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"좀 과격하긴 했나? 이번 달도 시말서 1위는 확정이네.","JPN":"ちょっと過激だったかな？　今月も始末書1位は確定ね。","ENG":"Maybe I went a little too far this time? And with that, I guess I'll be the employee of the month again. In the opposite way...","TWN":"做得太過火了嗎？這下我的悔過書也是這個月第一名了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"일단 율무차라도 한 잔 하면서 시말서 내용을 고민해보실까......","JPN":"とりあえず、お茶でも飲みながら始末書の内容を考えてみようかな……","ENG":"I might as well have a cup of tea and start practicing my sorry face.","TWN":"總之先喝杯薏仁茶，再煩惱悔過書該寫什麼吧……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Hmm?","TWN":"哎呀？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 안녕하세요. 귀여운 아가씨.","JPN":"こんにちは。可愛いお嬢さん。","ENG":"Hah hah, hello there, little lady.","TWN":"哈哈，妳好啊。可愛的女孩。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"여긴 들어오시면 안 되요. 길을 잃으신 것 같은데 민원 접수를 하려면 저쪽으로 가보세요.","JPN":"ここに入ったらダメですよ。\\n道に迷ったようですが、相談窓口ならあちらに行ってください。","ENG":"I'm afraid you can't be in here. Are you lost? Head over there if you came to file a complaint.","TWN":"不可以進來這裡喔。妳似乎迷路了呢，要陳情的話走那邊喔。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여기가 제 4특별기동수사대인가?","JPN":"ここが第4特別機動捜査隊なの？","ENG":"Are you part of SWAT 4?","TWN":"這裡是第四特遣機動隊嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어라? 그건 어떻게 아셨어요?","JPN":"あれ？　どうやって知ったんですか？","ENG":"Huh? How did you know?","TWN":"咦？妳怎麼知道？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};